const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const DEPLOYMENT_CONFIG = {
  production: {
    host: process.env.PROD_HOST,
    user: process.env.PROD_USER,
    port: process.env.PROD_PORT || 22,
    deployPath: process.env.DEPLOY_PATH || '/var/www/app',
    sshKey: process.env.SSH_KEY_PATH || '~/.ssh/id_rsa'
  }
};

const SECRET_ENV_VARS = [
  'PROD_HOST',
  'PROD_USER', 
  'PROD_PORT',
  'DEPLOY_PATH',
  'SSH_KEY_PATH'
];

function validateEnvironment() {
  const missing = SECRET_ENV_VARS.filter(env => !process.env[env]);
  if (missing.length > 0) {
    throw new Error(`Missing required environment variables: ${missing.join(', ')}`);
  }
}

function validateInput(input) {
  if (!input || typeof input !== 'string') return false;
  const allowedPattern = /^[a-zA-Z0-9._-]+$/;
  return allowedPattern.test(input);
}

function runCommand(command, options = {}) {
  try {
    console.log(`Running: ${command}`);
    const result = execSync(command, { 
      encoding: 'utf8',
      stdio: 'pipe',
      ...options 
    });
    console.log(result);
    return result;
  } catch (error) {
    console.error(`Command failed: ${command}`);
    console.error(error.message);
    throw error;
  }
}

function installDependencies() {
  console.log('Installing dependencies...');
  runCommand('npm ci --prefer-offline --no-audit');
}

function runTests() {
  console.log('Running tests...');
  runCommand('npm test');
}

function buildApplication() {
  console.log('Building application...');
  runCommand('npm run build');
}

function generateSBOM() {
  console.log('Generating SBOM...');
  try {
    const sbomPath = path.join(process.cwd(), 'sbom.json');
    const sbomContent = {
      version: '1.0',
      components: [],
      timestamp: new Date().toISOString()
    };
    
    const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf8'));
    const dependencies = packageJson.dependencies || {};
    
    Object.keys(dependencies).forEach(dep => {
      sbomContent.components.push({
        name: dep,
        version: dependencies[dep],
        type: 'library'
      });
    });
    
    fs.writeFileSync(sbomPath, JSON.stringify(sbomContent, null, 2));
    console.log('SBOM generated successfully');
  } catch (error) {
    console.error('Failed to generate SBOM:', error.message);
    throw error;
  }
}

function deployToProduction() {
  console.log('Deploying to production...');
  const config = DEPLOYMENT_CONFIG.production;
  
  if (!validateInput(config.host) || !validateInput(config.user)) {
    throw new Error('Invalid deployment configuration');
  }
  
  const deployCommand = `
    ssh -i ${config.sshKey} -p ${config.port} ${config.user}@${config.host} \\
    "mkdir -p ${config.deployPath} && \\
    cd ${config.deployPath} && \\
    rm -rf * && \\
    scp -i ${config.sshKey} -P ${config.port} -r ${process.cwd()}/* ${config.user}@${config.host}:${config.deployPath}/"
  `;
  
  runCommand(deployCommand);
}

function main() {
  try {
    validateEnvironment();
    installDependencies();
    runTests();
    generateSBOM();
    buildApplication();
    deployToProduction();
    console.log('Deployment completed successfully');
  } catch (error) {
    console.error('Deployment failed:', error.message);
    process.exit(1);
  }
}

main();